.chapter-reader-header {
    display: flex;
    align-items: flex-start;
    gap: 12px;
    padding: 20px 0 16px;
    border-bottom: 1px solid var(--border-light);
    margin-bottom: 24px;
}

.chapter-reader-back {
    width: 36px;
    height: 36px;
    border: none;
    background: var(--bg-secondary);
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: background-color 0.12s ease;
    flex-shrink: 0;
    margin-top: 2px;
}

.chapter-reader-back:hover {
    background: var(--bg-hover);
}

.chapter-reader-header-info {
    min-width: 0;
}

.chapter-reader-chapter-label {
    font-size: 0.75rem;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    font-weight: 500;
}

.chapter-reader-title {
    font-size: 1.3rem;
    font-weight: 700;
    color: var(--text-primary);
    margin: 4px 0 0 0;

