import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../../Context/useAuth';
import { useInfiniteQuery } from '@tanstack/react-query';
import { getStories } from '../../../../API/StoryApi';
import { motion } from 'framer-motion';
import { BeatLoader } from 'react-spinners';
import './StoryBrowser.css';

const STATUS_LABELS = { ongoing: 'Ongoing', completed: 'Completed', hiatus: 'Hiatus' };
const STATUS_FILTERS = [
    { value: null, label: 'All' },
    { value: 'ongoing', label: 'Ongoing' },
    { value: 'completed', label: 'Completed' },
    { value: 'hiatus', label: 'Hiatus' },
];

const StoryCard = ({ story, onClick }) => {
    const author = story.users;
    return (
        <motion.div
            className="story-card"
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            whileHover={{ y: -3 }}
            onClick={onClick}
        >
            <div className="story-card-cover">
                {story.cover_url ? (
                    <img src={story.cover_url} alt={story.title} loading="lazy" />
                ) : (
                    <div className="story-card-cover-placeholder">
                        <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="var(--text-muted)">
                            <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
                        </svg>
                    </div>
                )}
            </div>
            <div className="story-card-info">
                <h3 className="story-card-title">{story.title}</h3>
                {author && (
                    <div className="story-card-author">
                        {author.image_url && <img src={author.image_url} alt="" className="story-card-author-avatar" />}
                        <span>{author.name}</span>
                    </div>
                )}
                <div className="story-card-meta">
                    <span className={`story-status-badge story-status-${story.status}`}>
                        {STATUS_LABELS[story.status] || story.status}
                    </span>
                    <span className="story-card-stats">
                        {(story.vote_count || 0)} votes &middot; {(story.read_count || 0)} reads
                    </span>
                </div>
                {story.tags && story.tags.length > 0 && (
                    <div className="story-card-tags">
                        {story.tags.slice(0, 3).map(tag => (
                            <span key={tag} className="story-card-tag">{tag}</span>
                        ))}
                    </div>
                )}
            </div>
        </motion.div>
    );
};

const StoryBrowser = () => {
    const navigate = useNavigate();
    const { session } = useAuth();
    const token = session?.access_token;
    const [statusFilter, setStatusFilter] = useState(null);

    const {
        data,
        isLoading,
        hasNextPage,
        fetchNextPage,
        isFetchingNextPage,
    } = useInfiniteQuery({
        queryKey: ['storiesBrowse', statusFilter],
        queryFn: ({ pageParam = null }) => getStories(12, pageParam, statusFilter, null, token),
        getNextPageParam: (lastPage) => {
            if (!lastPage?.hasMore || !lastPage.data?.length) return undefined;
            return lastPage.data[lastPage.data.length - 1].created_at;
        },
        initialPageParam: null,
        refetchOnWindowFocus: false,
    });

    const stories = data?.pages?.flatMap(p => p.data) || [];

    return (
        <div className="story-browser">
            <div className="story-browser-header">
                <h2 className="story-browser-title">Stories</h2>
                {session && (
                    <div className="story-browser-header-actions">
                        <button
                            className="story-browser-my-btn"
                            onClick={() => navigate('/home/stories/dashboard')}
                        >
                            My Stories
                        </button>
                        <button
                            className="story-browser-new-btn"
                            onClick={() => navigate('/home/stories/new')}
                        >
                            + Write
                        </button>
                    </div>
                )}
            </div>

            <div className="story-browser-filters">
                {STATUS_FILTERS.map(f => (
                    <button
                        key={f.label}
                        className={`story-filter-btn ${statusFilter === f.value ? 'story-filter-btn-active' : ''}`}
                        onClick={() => setStatusFilter(f.value)}
                    >
                        {f.label}
                    </button>
                ))}
            </div>

            {isLoading ? (
                <div className="story-browser-loading">
                    <BeatLoader size={10} color="var(--text-muted)" />
                </div>
            ) : stories.length === 0 ? (
                <div className="story-browser-empty">
                    <p>No stories found.</p>
                </div>
            ) : (
                <>
                    <div className="story-browser-grid">
                        {stories.map(story => (
                            <StoryCard
                                key={story.id}
                                story={story}
                                onClick={() => navigate(`/home/stories/${story.id}`)}
                            />
                        ))}
                    </div>
                    {hasNextPage && (
                        <div className="story-browser-load-more">
                            <button
                                className="story-browser-load-more-btn"
                                onClick={() => fetchNextPage()}
                                disabled={isFetchingNextPage}
                            >
                                {isFetchingNextPage ? (
                                    <BeatLoader size={8} color="var(--text-secondary)" />
                                ) : (
                                    'Load more'
                                )}
                            </button>
                        </div>
                    )}
                </>
            )}
        </div>
    );
};

export default StoryBrowser;

import React from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useAuth } from '../../../Context/useAuth';
import { useStoryDetail } from '../hooks/useStoryData';
import { useToggleVote, useToggleLibrary } from '../hooks/useStoryMutations';
import { motion } from 'framer-motion';
import { BeatLoader } from 'react-spinners';
import './StoryDetail.css';

const STATUS_LABELS = { ongoing: 'Ongoing', completed: 'Completed', hiatus: 'Hiatus' };

const StoryDetail = () => {
    const { storyId } = useParams();
    const navigate = useNavigate();
    const { session, openAuthModal } = useAuth();
    const token = session?.access_token;

    const { data: story, isLoading } = useStoryDetail(storyId, token);
    const voteMutation = useToggleVote(token);
    const libraryMutation = useToggleLibrary(token);

    const handleVote = () => {
        if (!session) return openAuthModal();
        voteMutation.mutate(storyId);
    };

    const handleLibrary = () => {
        if (!session) return openAuthModal();
        libraryMutation.mutate(storyId);
    };

    const handleStartReading = () => {
        // If there's reading progress, resume from there
        if (story?.reading_progress?.chapter_id) {
            navigate(`/home/stories/${storyId}/chapter/${story.reading_progress.chapter_id}`);
            return;
        }
        // Otherwise start from first published chapter
        const firstChapter = story?.chapters?.[0];
        if (firstChapter) {
            navigate(`/home/stories/${storyId}/chapter/${firstChapter.id}`);
        }
    };

    if (isLoading) {
        return (
            <div className="story-detail">
                <div className="story-detail-loading">
                    <BeatLoader size={10} color="var(--text-muted)" />
                </div>
            </div>
        );
    }

    if (!story) {
        return (
            <div className="story-detail">
                <p className="story-detail-error">Story not found.</p>
            </div>
        );
    }

    const author = story.users;
    const chapters = story.chapters || [];
    const hasProgress = !!story.reading_progress;
    const totalWords = chapters.reduce((sum, ch) => sum + (ch.word_count || 0), 0);

    return (
        <motion.div
            className="story-detail"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.2 }}
        >
            {/* Hero section */}
            <div className="story-detail-hero">
                <div className="story-detail-cover">
                    {story.cover_url ? (
                        <img src={story.cover_url} alt={story.title} />
                    ) : (
                        <div className="story-detail-cover-placeholder">
                            <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="var(--text-muted)">
                                <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
                            </svg>
                        </div>
                    )}
                </div>
                <div className="story-detail-hero-info">
                    <h1 className="story-detail-title">{story.title}</h1>
                    {author && (
                        <div
                            className="story-detail-author"
                            onClick={() => author.username ? navigate(`/u/${author.username}`) : null}
                        >
                            {author.image_url && (
                                <img src={author.image_url} alt="" className="story-detail-author-avatar" />
                            )}
                            <span className="story-detail-author-name">{author.name}</span>
                        </div>
                    )}
                    <div className="story-detail-stats">
                        <span className={`story-status-badge story-status-${story.status}`}>
                            {STATUS_LABELS[story.status] || story.status}
                        </span>
                        <span>{chapters.length} chapter{chapters.length !== 1 ? 's' : ''}</span>
                        <span>{totalWords.toLocaleString()} words</span>
                        <span>{(story.read_count || 0).toLocaleString()} reads</span>
                        <span>{(story.vote_count || 0).toLocaleString()} votes</span>
                    </div>
                    {story.tags && story.tags.length > 0 && (
                        <div className="story-detail-tags">
                            {story.tags.map(tag => (
                                <span key={tag} className="story-detail-tag">{tag}</span>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            {/* Action buttons */}
            <div className="story-detail-actions">
                {chapters.length > 0 && (
                    <button className="story-detail-read-btn" onClick={handleStartReading}>
                        {hasProgress ? 'Continue Reading' : 'Start Reading'}
                    </button>
                )}
                <button
                    className={`story-detail-vote-btn ${story.has_voted ? 'story-detail-vote-btn-active' : ''}`}
                    onClick={handleVote}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill={story.has_voted ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2">
                        <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/>
                    </svg>
                    {story.vote_count || 0}
                </button>
                <button
                    className={`story-detail-library-btn ${story.in_library ? 'story-detail-library-btn-active' : ''}`}
                    onClick={handleLibrary}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill={story.in_library ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2">
                        <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"/>
                    </svg>
                    {story.in_library ? 'In Library' : 'Add to Library'}
                </button>
            </div>

            {/* Description */}
            {story.description && (
                <div className="story-detail-description">
                    <h3>About</h3>
                    <p>{story.description}</p>
                </div>
            )}

            {/* Chapter list */}
            <div className="story-detail-chapters">
                <h3>Chapters ({chapters.length})</h3>
                {chapters.length === 0 ? (
                    <p className="story-detail-no-chapters">No chapters published yet.</p>
                ) : (
                    <div className="story-detail-chapter-list">
                        {chapters.map((ch) => (
                            <div
                                key={ch.id}
                                className="story-detail-chapter-item"
                                onClick={() => navigate(`/home/stories/${storyId}/chapter/${ch.id}`)}
                            >
                                <div className="story-detail-chapter-left">
                                    <span className="story-detail-chapter-number">Ch. {ch.chapter_number}</span>
                                    <span className="story-detail-chapter-title">{ch.title}</span>
                                </div>
                                <div className="story-detail-chapter-right">
                                    <span className="story-detail-chapter-words">{(ch.word_count || 0).toLocaleString()} words</span>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </motion.div>
    );
};

export default StoryDetail;

