108→export const getCommentsService = async (chapterId, paragraphIndex) => {
109→    if (!chapterId) {
110→        throw { status: 400, error: 'chapterId is required' };
111→    }
112→
113→    let query = supabase
114→        .from('story_comments')
115→        .select(`*, users(id, name, image_url, username, badge)`)
116→        .eq('chapter_id', chapterId)
117→        .is('parent_id', null)
118→        .order('created_at', { ascending: true });
119→
120→    if (paragraphIndex !== undefined && paragraphIndex !== null) {
121→        query = query.eq('paragraph_index', parseInt(paragraphIndex));
122→    }
123→
124→    const { data: comments, error } = await query;
125→
126→    if (error) {
127→        console.error('supabase error fetching comments:', error.message);
128→        throw { status: 500, error: 'failed to fetch comments' };
129→    }
130→
131→    // Fetch replies for all top-level comments
132→    if (comments && comments.length > 0) {
133→        const commentIds = comments.map(c => c.id);
134→        const { data: replies, error: replyError } = await supabase
135→            .from('story_comments')
136→            .select(`*, users(id, name, image_url, username, badge)`)
137→            .in('parent_id', commentIds)
138→            .order('created_at', { ascending: true });
139→
140→        if (!replyError && replies) {
141→            const replyMap = {};
142→            replies.forEach(r => {
143→                if (!replyMap[r.parent_id]) replyMap[r.parent_id] = [];
144→                replyMap[r.parent_id].push(r);
145→            });
146→            comments.forEach(c => {
147→                c.replies = replyMap[c.id] || [];
148→            });
149→        }
150→    }
151→
152→    return comments || [];
153→};
