181→export const addCommentService = async (chapterId, userId, comment, paragraphIndex, paragraphFingerprint, parentId) => {
182→    if (!chapterId || !userId) {
183→        throw { status: 400, error: 'chapterId and userId are required' };
184→    }
185→    if (!comment || typeof comment !== 'string' || comment.trim().length === 0) {
186→        throw { status: 400, error: 'comment is required' };
187→    }
188→    if (comment.length > 300) {
189→        throw { status: 400, error: 'comment must be 300 characters or less' };
190→    }
191→
192→    const insertData = {
193→        chapter_id: chapterId,
194→        user_id: userId,
195→        comment: comment.trim(),
196→        paragraph_index: paragraphIndex !== undefined ? parseInt(paragraphIndex) : -1,
197→        paragraph_fingerprint: paragraphFingerprint || null,
198→        parent_id: parentId || null,
199→    };
200→
201→    const { data, error } = await supabase
202→        .from('story_comments')
203→        .insert(insertData)
204→        .select(`*, users(id, name, image_url, username, badge)`)
205→        .single();
206→
207→    if (error) {
208→        console.error('supabase error adding comment:', error.message);
209→        throw { status: 500, error: 'failed to add comment' };
210→    }
211→
212→    return data;
213→};
