  3→// ── Vote toggle ──
  4→export const toggleVoteService = async (storyId, userId) => {
  5→    if (!storyId || !userId) {
  6→        throw { status: 400, error: 'storyId and userId are required' };
  7→    }
  8→
  9→    const { data: existing } = await supabase
 10→        .from('story_votes')
 11→        .select('id')
 12→        .eq('story_id', storyId)
 13→        .eq('user_id', userId)
 14→        .maybeSingle();
 15→
 16→    if (!existing) {
 17→        const { error } = await supabase
 18→            .from('story_votes')
 19→            .insert({ story_id: storyId, user_id: userId });
 20→
 21→        if (error) {
 22→            console.error('supabase error inserting vote:', error.message);
 23→            throw { status: 500, error: 'failed to vote' };
 24→        }
 25→
 26→        // Increment vote_count
 27→        const { data: story } = await supabase
 28→            .from('stories')
 29→            .select('vote_count')
 30→            .eq('id', storyId)
 31→            .single();
 32→        if (story) {
 33→            await supabase
 34→                .from('stories')
 35→                .update({ vote_count: (story.vote_count || 0) + 1 })
 36→                .eq('id', storyId);
 37→        }
 38→
 39→        return { message: 'voted' };
 40→    } else {
 41→        const { error } = await supabase
 42→            .from('story_votes')
 43→            .delete()
 44→            .eq('story_id', storyId)
 45→            .eq('user_id', userId);
 46→
 47→        if (error) {
 48→            console.error('supabase error deleting vote:', error.message);
 49→            throw { status: 500, error: 'failed to unvote' };
 50→        }
 51→
 52→        // Decrement vote_count
 53→        const { data: story } = await supabase
 54→            .from('stories')
 55→            .select('vote_count')
 56→            .eq('id', storyId)
 57→            .single();
 58→        if (story) {
 59→            await supabase
 60→                .from('stories')
 61→                .update({ vote_count: Math.max(0, (story.vote_count || 0) - 1) })
 62→                .eq('id', storyId);
 63→        }
 64→
 65→        return { message: 'unvoted' };
 66→    }
 67→};
 68→
 69→// ── Library toggle ──
 70→export const toggleLibraryService = async (storyId, userId) => {
 71→    if (!storyId || !userId) {
 72→        throw { status: 400, error: 'storyId and userId are required' };
 73→    }
 74→
 75→    const { data: existing } = await supabase
 76→        .from('story_library')
 77→        .select('id')
 78→        .eq('story_id', storyId)
 79→        .eq('user_id', userId)
 80→        .maybeSingle();
 81→
 82→    if (!existing) {
 83→        const { error } = await supabase
 84→            .from('story_library')
 85→            .insert({ story_id: storyId, user_id: userId });
 86→
 87→        if (error) {
 88→            console.error('supabase error adding to library:', error.message);
 89→            throw { status: 500, error: 'failed to add to library' };
 90→        }
 91→        return { message: 'added' };
 92→    } else {
 93→        const { error } = await supabase
 94→            .from('story_library')
 95→            .delete()
 96→            .eq('story_id', storyId)
 97→            .eq('user_id', userId);
 98→
 99→        if (error) {
100→            console.error('supabase error removing from library:', error.message);
101→            throw { status: 500, error: 'failed to remove from library' };
102→        }
103→        return { message: 'removed' };
104→    }
105→};
106→
107→// ── Comments ──
108→export const getCommentsService = async (chapterId, paragraphIndex) => {
109→    if (!chapterId) {
110→        throw { status: 400, error: 'chapterId is required' };
111→    }
112→
113→    let query = supabase
114→        .from('story_comments')
115→        .select(`*, users(id, name, image_url, username, badge)`)
116→        .eq('chapter_id', chapterId)
117→        .is('parent_id', null)
118→        .order('created_at', { ascending: true });
119→
120→    if (paragraphIndex !== undefined && paragraphIndex !== null) {
121→        query = query.eq('paragraph_index', parseInt(paragraphIndex));
122→    }
123→
124→    const { data: comments, error } = await query;
125→
126→    if (error) {
127→        console.error('supabase error fetching comments:', error.message);
128→        throw { status: 500, error: 'failed to fetch comments' };
129→    }
130→
131→    // Fetch replies for all top-level comments
132→    if (comments && comments.length > 0) {
133→        const commentIds = comments.map(c => c.id);
134→        const { data: replies, error: replyError } = await supabase
135→            .from('story_comments')
136→            .select(`*, users(id, name, image_url, username, badge)`)
137→            .in('parent_id', commentIds)
138→            .order('created_at', { ascending: true });
139→
140→        if (!replyError && replies) {
141→            const replyMap = {};
142→            replies.forEach(r => {
143→                if (!replyMap[r.parent_id]) replyMap[r.parent_id] = [];
144→                replyMap[r.parent_id].push(r);
